// HasLionUsers applies the HasEdge predicate on the "lion_users" edge.
func HasLionUsers() predicate.UserMemberships {
	return predicate.UserMemberships(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, LionUsersTable, LionUsersColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasLionUsersWith applies the HasEdge predicate on the "lion_users" edge with a given conditions (other predicates).
func HasLionUsersWith(preds ...predicate.Users) predicate.UserMemberships {
	return predicate.UserMemberships(func(s *sql.Selector) {
		step := newLionUsersStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UserMemberships) predicate.UserMemberships {
	return predicate.UserMemberships(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UserMemberships) predicate.UserMemberships {
	return predicate.UserMemberships(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UserMemberships) predicate.UserMemberships {
	return predicate.UserMemberships(sql.NotPredicates(p))
}
